use std::thread;
use std::time::Duration;

fn main() {
    let handle = thread::spawn(|| {
        for i in 1..=3 {
            println!("thread: {}", i);
            thread::sleep(Duration::from_millis(1));
        }
    });

    for i in 1..=3 {
        println!("main: {}", i);
    }

    handle.join().unwrap();
}

use std::thread;

fn main() {
    let message = String::from("Hello from main thread");
    let handle = thread::spawn(move || {
        println!("{}", message);
    });
    handle.join().unwrap();
}

use std::sync::Arc;
use std::thread;

fn main() {
    let data = Arc::new(vec![1, 2, 3, 4, 5]);
    let mut handles = vec![];
    for i in 0..3 {
        let data = Arc::clone(&data);
        let h = thread::spawn(move || {
            println!("thread {}: sum = {}", i, data.iter().sum::<i32>());
        });
        handles.push(h);
    }
    for h in handles { h.join().unwrap(); }
}

use std::sync::{Arc, Mutex};
use std::thread;

fn main() {
    let counter = Arc::new(Mutex::new(0));
    let mut handles = vec![];
    for _ in 0..5 {
        let counter = Arc::clone(&counter);
        handles.push(thread::spawn(move || {
            *counter.lock().unwrap() += 1;
        }));
    }
    for h in handles { h.join().unwrap(); }
    println!("result: {}", *counter.lock().unwrap());
}

use std::sync::mpsc;
use std::thread;

fn main() {
    let (tx, rx) = mpsc::channel();
    thread::spawn(move || {
        for i in 1..=3 {
            tx.send(i).unwrap();
        }
    });
    for received in rx {
        println!("got: {}", received);
    }
}

use std::sync::mpsc;
use std::thread;

fn main() {
    let (tx, rx) = mpsc::channel();
    for i in 0..3 {
        let tx = tx.clone();
        thread::spawn(move || {
            tx.send(format!("msg from {}", i)).unwrap();
        });
    }
    drop(tx); // drop original so rx iterator can end
    let mut msgs: Vec<String> = rx.collect();
    msgs.sort();
    for m in &msgs { println!("{}", m); }
}

use std::thread;

fn main() {
    let data = vec![1, 2, 3, 4, 5, 6, 7, 8];
    let result = thread::scope(|s| {
        let h1 = s.spawn(|| data[..4].iter().sum::<i32>());
        let h2 = s.spawn(|| data[4..].iter().sum::<i32>());
        h1.join().unwrap() + h2.join().unwrap()
    });
    println!("parallel sum: {}", result);
}

use std::sync::{Arc, Mutex};

// Arc<Mutex<T>> is Send + Sync if T: Send
// Rc<T> is neither — single-threaded only

fn is_send<T: Send>(_: T) {}
fn is_sync<T: Sync>(_: &T) {}

fn main() {
    let arc_mutex = Arc::new(Mutex::new(42));
    is_send(arc_mutex.clone());
    is_sync(&arc_mutex);
    println!("Arc<Mutex<i32>> is Send and Sync");
}
